import tempfile, time, threading
from cache_decorator import disk_cache, DiskCache

# --- test 1: decorator interface ---
@disk_cache(cache_dir=tempfile.mkdtemp(), ttl=3600)
def add(a, b):
    return a + b

assert add(1, 2) == 3
assert add(1, 2) == 3  # from cache

# --- test 2: class interface ---
d = DiskCache(cache_dir=tempfile.mkdtemp(), ttl=0)

@d
def mul(x, y):
    return x * y

assert mul(3, 4) == 12
assert mul(3, 4) == 12  # from cache

# --- test 3: TTL expiry ---
td = tempfile.mkdtemp()
c = DiskCache(cache_dir=td, ttl=1)

@c
def now():
    return time.monotonic()

v1 = now()
time.sleep(1.1)
v2 = now()
assert v2 > v1, 'TTL did not expire'

# --- test 4: unhashable args ---
@disk_cache(cache_dir=tempfile.mkdtemp(), ttl=0)
def with_list(items):
    return sum(items)

assert with_list([1, 2, 3]) == 6
assert with_list([1, 2, 3]) == 6  # from cache

# --- test 5: clear ---
td2 = tempfile.mkdtemp()
c2 = DiskCache(cache_dir=td2, ttl=0)

@c2
def f(x):
    return x * 2

assert f(42) == 84
c2.clear()
# After clear, call again should still work (recomputes)
assert f(42) == 84

# --- test 6: thread safety ---
td3 = tempfile.mkdtemp()
c3 = DiskCache(cache_dir=td3, ttl=0)

@c3
def double(x):
    return x * 2

errors = []
def worker():
    for i in range(50):
        try:
            assert double(i) == i * 2
        except Exception as e:
            errors.append(e)

threads = [threading.Thread(target=worker) for _ in range(8)]
for t in threads: t.start()
for t in threads: t.join()
assert not errors, f'thread safety failed: {errors}'

print('ALL TESTS PASSED')
